import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Screen = 'home' | 'map' | 'saved' | 'alerts' | 'chat' | 'scanner';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

export interface ASPStatus {
  status: string;
  date: string;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const askNYCStreetRules = async (prompt: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are an expert NYC parking and street rules assistant. Provide clear, concise answers to questions about NYC parking regulations, alternate side parking (ASP), parking tickets, and traffic. Always warn users to verify with physical signs.",
      },
    });
    return response.text || "I'm sorry, I couldn't process that request.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: Unable to connect to the NYC rules database. Please try again later.";
  }
};

export const scanSignRules = async (imageBase64: string) => {
  try {
    const imagePart = {
      inlineData: {
        mimeType: 'image/jpeg',
        data: imageBase64,
      },
    };
    const textPart = {
      text: "Analyze this NYC parking sign. Explain exactly what the rules are for the current day and time. Be very specific about hours and days mentioned on the sign."
    };

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [imagePart, textPart] },
    });

    return response.text || "I couldn't read the rules from this sign image.";
  } catch (error) {
    console.error("Gemini OCR Error:", error);
    return "Failed to analyze sign. Please ensure the image is clear and well-lit.";
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { Screen, Message } from './types';
import HomeView from './components/HomeView';
import ChatView from './components/ChatView';
import ScannerView from './components/ScannerView';
import BottomNav from './components/BottomNav';
import TopBar from './components/TopBar';

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<Screen>('home');
  const [chatHistory, setChatHistory] = useState<Message[]>([]);
  const [initialPrompt, setInitialPrompt] = useState<string>('');

  const navigateTo = useCallback((screen: Screen) => {
    setCurrentScreen(screen);
    window.scrollTo(0, 0);
  }, []);

  const startChat = useCallback((prompt?: string) => {
    if (prompt) setInitialPrompt(prompt);
    navigateTo('chat');
  }, [navigateTo]);

  const renderScreen = () => {
    switch (currentScreen) {
      case 'home':
        return <HomeView onStartChat={startChat} onStartScan={() => navigateTo('scanner')} />;
      case 'chat':
        return <ChatView initialPrompt={initialPrompt} history={chatHistory} setHistory={setChatHistory} onBack={() => navigateTo('home')} />;
      case 'scanner':
        return <ScannerView onBack={() => navigateTo('home')} onAnalysisResult={(res) => {
          setChatHistory([{ id: Date.now().toString(), role: 'assistant', content: `Analysis of your scanned sign:\n\n${res}` }]);
          navigateTo('chat');
        }} />;
      case 'map':
        return <div className="p-10 text-center font-bold text-slate-400">Map feature coming soon!</div>;
      case 'saved':
        return <div className="p-10 text-center font-bold text-slate-400">Your saved rules will appear here.</div>;
      case 'alerts':
        return <div className="p-10 text-center font-bold text-slate-400">No active alerts for your area.</div>;
      default:
        return <HomeView onStartChat={startChat} onStartScan={() => navigateTo('scanner')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-md mx-auto bg-background-light shadow-xl">
      {currentScreen !== 'chat' && currentScreen !== 'scanner' && <TopBar />}

      <main className="flex-grow pb-24">
        {renderScreen()}
      </main>

      <BottomNav currentScreen={currentScreen} onNavigate={navigateTo} />
    </div>
  );
};

export default App;

