import React, { useState, useEffect, useRef } from 'react';
import { Message } from '../types';
import { askNYCStreetRules } from '../services/geminiService';

interface ChatViewProps {
  initialPrompt: string;
  history: Message[];
  setHistory: React.Dispatch<React.SetStateAction<Message[]>>;
  onBack: () => void;
}

const ChatView: React.FC<ChatViewProps> = ({ initialPrompt, history, setHistory, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (initialPrompt && history.length === 0) {
      handleSend(initialPrompt);
    }
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  const handleSend = async (text: string) => {
    if (!text.trim()) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text };
    setHistory(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const response = await askNYCStreetRules(text);
    const aiMsg: Message = { id: (Date.now() + 1).toString(), role: 'assistant', content: response };
    setHistory(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100dvh-64px)] bg-slate-50">
      <div className="flex items-center p-4 border-b bg-white">
        <button onClick={onBack} className="mr-4 text-slate-600">
          <span className="material-symbols-outlined">arrow_back</span>
        </button>
        <h2 className="font-bold">NYC Rules Assistant</h2>
      </div>

      <div className="flex-grow overflow-y-auto p-4 space-y-4">
        {history.map(msg => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${msg.role === 'user' ? 'bg-primary text-white' : 'bg-white border text-slate-800'}`}>
              <p className="text-sm whitespace-pre-wrap leading-relaxed">{msg.content}</p>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border p-4 rounded-2xl flex items-center gap-2">
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
              <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
            </div>
          </div>
        )}
        <div ref={scrollRef} />
      </div>

      <div className="p-4 bg-white border-t">
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSend(input); }}
          className="flex items-center gap-2"
        >
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your question..."
            className="flex-grow bg-slate-100 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-primary"
            disabled={loading}
          />
          <button 
            type="submit"
            disabled={loading || !input.trim()}
            className="bg-primary text-white p-3 rounded-xl disabled:opacity-50"
          >
            <span className="material-symbols-outlined">send</span>
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatView;

import React, { useRef, useState, useEffect } from 'react';
import { scanSignRules } from '../services/geminiService';

interface ScannerViewProps {
  onBack: () => void;
  onAnalysisResult: (result: string) => void;
}

const ScannerView: React.FC<ScannerViewProps> = ({ onBack, onAnalysisResult }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [scanning, setScanning] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const s = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment' } 
        });
        setStream(s);
        if (videoRef.current) {
          videoRef.current.srcObject = s;
        }
      } catch (err) {
        console.error("Camera access error:", err);
        setError("Camera access denied. Please enable camera permissions.");
      }
    };

    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const takePhoto = async () => {
    if (!videoRef.current || !canvasRef.current || scanning) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/jpeg');
    const base64 = dataUrl.split(',')[1];

    setScanning(true);
    const result = await scanSignRules(base64);
    setScanning(false);
    onAnalysisResult(result);
  };

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col">
      <div className="p-4 flex items-center justify-between text-white bg-black/50 absolute top-0 w-full z-10">
        <button onClick={onBack} className="p-2 bg-white/10 rounded-full">
          <span className="material-symbols-outlined">close</span>
        </button>
        <h2 className="font-bold">Scan Parking Sign</h2>
        <div className="w-10"></div>
      </div>

      <div className="flex-grow relative overflow-hidden flex items-center justify-center">
        {error ? (
          <div className="text-white text-center p-10 space-y-4">
            <span className="material-symbols-outlined text-6xl text-red-500">error</span>
            <p>{error}</p>
            <button onClick={onBack} className="px-6 py-2 bg-primary rounded-full">Go Back</button>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover"
            />
            {/* Scanner Frame Overlay */}
            <div className="absolute inset-0 border-[60px] border-black/40 pointer-events-none flex items-center justify-center">
              <div className="w-64 h-80 border-2 border-white/80 rounded-lg relative">
                <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary"></div>
                <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary"></div>
                <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary"></div>
                <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary"></div>
                {scanning && (
                  <div className="absolute top-0 left-0 w-full h-1 bg-primary/50 shadow-[0_0_15px_primary] animate-[scan_2s_infinite]"></div>
                )}
              </div>
            </div>
          </>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />

      <div className="p-10 bg-black flex flex-col items-center gap-4">
        <p className="text-white/70 text-sm text-center">Position the parking sign within the frame</p>
        <button 
          onClick={takePhoto}
          disabled={scanning || !!error}
          className="w-20 h-20 rounded-full bg-white flex items-center justify-center border-8 border-white/20 hover:scale-105 transition-transform disabled:opacity-50"
        >
          {scanning ? (
             <div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <div className="w-14 h-14 rounded-full bg-white border-2 border-slate-300"></div>
          )}
        </button>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0; }
          50% { top: 100%; }
          100% { top: 0; }
        }
      `}</style>
    </div>
  );
};

export default ScannerView;

import React from 'react';
import { Screen } from '../types';

interface BottomNavProps {
  currentScreen: Screen;
  onNavigate: (screen: Screen) => void;
}

const BottomNav: React.FC<BottomNavProps> = ({ currentScreen, onNavigate }) => {
  const isNavVisible = ['home', 'map', 'saved', 'alerts'].includes(currentScreen);
  if (!isNavVisible) return null;

  const NavItem = ({ screen, icon, label }: { screen: Screen, icon: string, label: string }) => {
    const isActive = currentScreen === screen;
    return (
      <button 
        onClick={() => onNavigate(screen)}
        className="flex flex-col items-center justify-center w-16 gap-1 group"
      >
        <span className={`material-symbols-outlined text-[26px] transition-colors ${isActive ? 'text-primary fill-[1]' : 'text-slate-400 group-hover:text-slate-600'}`}>
          {icon}
        </span>
        <span className={`text-[10px] font-medium transition-colors ${isActive ? 'text-primary' : 'text-slate-400 group-hover:text-slate-600'}`}>
          {label}
        </span>
      </button>
    );
  };

  return (
    <div className="fixed bottom-0 w-full max-w-md bg-white/90 backdrop-blur-lg border-t border-slate-200 pb-safe pt-2 z-50">
      <div className="flex justify-around items-center h-16">
        <NavItem screen="home" icon="home" label="Home" />
        <NavItem screen="map" icon="map" label="Map" />
        <NavItem screen="saved" icon="bookmark" label="Saved" />
        <NavItem screen="alerts" icon="notifications" label="Alerts" />
      </div>
      <div className="h-4 w-full"></div>
    </div>
  );
};

export default BottomNav;
